using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly FakePaymentProcessor _processor = new();
    private readonly Payments.PaymentGateway _sut;

    public PaymentGatewayTests()
    {
        _sut = new Payments.PaymentGateway(_processor);
    }

    // ── Constructor ──────────────────────────────────────────

    [TestMethod]
    public void Constructor_NullProcessor_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => new Payments.PaymentGateway(null!));
    }

    // ── ChargeAsync: happy path ──────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidInput_ReturnsSuccessResult()
    {
        _processor.ChargeResult = new ChargeResult("ch_123", true);

        var result = await _sut.ChargeAsync("tok_valid", 50.00m);

        Assert.AreEqual("ch_123", result.ChargeId);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    [DataRow(0.01, DisplayName = "Minimum amount")]
    [DataRow(999_999.99, DisplayName = "Maximum amount")]
    [DataRow(100.50, DisplayName = "Typical amount")]
    public async Task ChargeAsync_ValidAmounts_DoesNotThrow(double amount)
    {
        _processor.ChargeResult = new ChargeResult("ch_ok", true);

        var result = await _sut.ChargeAsync("tok_valid", (decimal)amount);

        Assert.IsNotNull(result);
    }

    // ── ChargeAsync: invalid card token ──────────────────────

    [TestMethod]
    [DataRow(null, DisplayName = "Null token")]
    [DataRow("", DisplayName = "Empty token")]
    [DataRow("   ", DisplayName = "Whitespace token")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.ChargeAsync(token!, 10m));
    }

    // ── ChargeAsync: invalid amount ──────────────────────────

    [TestMethod]
    [DataRow(0, DisplayName = "Zero amount")]
    [DataRow(-1.00, DisplayName = "Negative amount")]
    [DataRow(1_000_000.00, DisplayName = "Exceeds maximum")]
    public async Task ChargeAsync_InvalidAmount_ThrowsArgumentOutOfRangeException(double amount)
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _sut.ChargeAsync("tok_valid", (decimal)amount));
    }

    // ── ChargeAsync: processor failure ───────────────────────

    [TestMethod]
    public async Task ChargeAsync_ProcessorReturnsFailure_ReturnsFalseSuccess()
    {
        _processor.ChargeResult = new ChargeResult("ch_fail", false);

        var result = await _sut.ChargeAsync("tok_valid", 25.00m);

        Assert.IsFalse(result.Success);
    }

    // ── RefundAsync: happy path ──────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessResult()
    {
        _processor.RefundResult = new RefundResult("re_456", true);

        var result = await _sut.RefundAsync("ch_123");

        Assert.AreEqual("re_456", result.RefundId);
        Assert.IsTrue(result.Success);
    }

    // ── RefundAsync: invalid charge ID ───────────────────────

    [TestMethod]
    [DataRow(null, DisplayName = "Null charge ID")]
    [DataRow("", DisplayName = "Empty charge ID")]
    [DataRow("   ", DisplayName = "Whitespace charge ID")]
    public async Task RefundAsync_InvalidChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _sut.RefundAsync(chargeId!));
    }

    // ── RefundAsync: processor failure ───────────────────────

    [TestMethod]
    public async Task RefundAsync_ProcessorReturnsFailure_ReturnsFalseSuccess()
    {
        _processor.RefundResult = new RefundResult("re_fail", false);

        var result = await _sut.RefundAsync("ch_123");

        Assert.IsFalse(result.Success);
    }

    // ── ProcessWebhook: known event types ────────────────────

    [TestMethod]
    [DataRow("charge.succeeded", true, "Charge confirmed", DisplayName = "Charge succeeded")]
    [DataRow("charge.failed", false, "Charge declined", DisplayName = "Charge failed")]
    [DataRow("refund.completed", true, "Refund processed", DisplayName = "Refund completed")]
    public void ProcessWebhook_KnownEventType_ReturnsExpectedResult(
        string eventType, bool expectedHandled, string expectedMessage)
    {
        var result = _sut.ProcessWebhook(eventType, "{\"id\":\"evt_1\"}");

        Assert.AreEqual(expectedHandled, result.Handled);
        Assert.AreEqual(expectedMessage, result.Message);
    }

    // ── ProcessWebhook: unknown event type ───────────────────

    [TestMethod]
    public void ProcessWebhook_UnknownEventType_ReturnsNotHandled()
    {
        var result = _sut.ProcessWebhook("invoice.created", "{}");

        Assert.IsFalse(result.Handled);
        StringAssert.Contains(result.Message, "Unknown event");
    }

    // ── ProcessWebhook: invalid inputs ───────────────────────

    [TestMethod]
    [DataRow(null, "{}", DisplayName = "Null event type")]
    [DataRow("", "{}", DisplayName = "Empty event type")]
    [DataRow("charge.succeeded", null, DisplayName = "Null payload")]
    [DataRow("charge.succeeded", "", DisplayName = "Empty payload")]
    public void ProcessWebhook_InvalidInput_ThrowsArgumentException(
        string? eventType, string? payload)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ProcessWebhook(eventType!, payload!));
    }

    // ── Fake implementation for testing ──────────────────────

    private sealed class FakePaymentProcessor : IPaymentProcessor
    {
        public ChargeResult ChargeResult { get; set; } = new("ch_default", true);
        public RefundResult RefundResult { get; set; } = new("re_default", true);

        public Task<ChargeResult> ProcessChargeAsync(string cardToken, decimal amount)
            => Task.FromResult(ChargeResult);

        public Task<RefundResult> ProcessRefundAsync(string chargeId)
            => Task.FromResult(RefundResult);
    }
}

